using System.Diagnostics;using AiVideoStudio.Application.Interfaces.Operations;using AiVideoStudio.Domain.Enums;
namespace AiVideoStudio.Api.Middlewares;
public sealed class ProductionSecurityMiddleware{private readonly RequestDelegate _next;public ProductionSecurityMiddleware(RequestDelegate next)=>_next=next;public async Task InvokeAsync(HttpContext context,IRateLimiter limiter){context.Items["RequestId"]=context.TraceIdentifier;context.Response.Headers["X-Request-Id"]=context.TraceIdentifier;context.Response.Headers["X-Content-Type-Options"]="nosniff";context.Response.Headers["X-Frame-Options"]="DENY";context.Response.Headers["Referrer-Policy"]="no-referrer";context.Response.Headers["Content-Security-Policy"]="default-src 'none'; frame-ancestors 'none'";var key=context.User.FindFirst("userId")?.Value??context.Connection.RemoteIpAddress?.ToString()??"anonymous";if(!limiter.TryAcquire(key)){context.Response.StatusCode=StatusCodes.Status429TooManyRequests;await context.Response.WriteAsJsonAsync(new{error="Rate limit exceeded.",requestId=context.TraceIdentifier});return;}await _next(context);}}
public sealed class RequestMetricsMiddleware{private readonly RequestDelegate _next;public RequestMetricsMiddleware(RequestDelegate next)=>_next=next;public async Task InvokeAsync(HttpContext context,IMetricsCollector metrics,IAuditWriter audit){var watch=Stopwatch.StartNew();var area=Area(context.Request.Path);try{await _next(context);metrics.Increment("api.requests");metrics.Increment($"api.status.{context.Response.StatusCode}");metrics.Increment($"{area}.requests");if(context.Request.Path.Value?.Contains("/retry",StringComparison.OrdinalIgnoreCase)==true)metrics.Increment("retries.total");if(context.Response.StatusCode>=400)metrics.Increment("failures.total");if(context.Request.Method is not("GET" or "HEAD" or "OPTIONS")){var user=context.User.FindFirst("userId")?.Value??"anonymous";await audit.WriteAsync(user,Action(context.Request.Method),context.Response.StatusCode<400?"Success":"Failed",context.Request.Path,context.RequestAborted);}}catch{metrics.Increment("api.failures");metrics.Increment("failures.total");throw;}finally{metrics.Observe("api.processing",watch.Elapsed);metrics.Observe($"{area}.processing",watch.Elapsed);}}
private static string Area(PathString path){var value=path.Value??string.Empty;if(value.Contains("workflow",StringComparison.OrdinalIgnoreCase))return "workflow";if(value.Contains("render",StringComparison.OrdinalIgnoreCase))return "render";if(value.Contains("export",StringComparison.OrdinalIgnoreCase))return "export";if(value.Contains("upload",StringComparison.OrdinalIgnoreCase))return "upload";return "api";}private static AuditActionType Action(string method)=>method switch{"POST"=>AuditActionType.Create,"PUT" or "PATCH"=>AuditActionType.Update,"DELETE"=>AuditActionType.Delete,_=>AuditActionType.Execute};}
